const job = $input.item.json;

const systemPrompt = `You are an expert technical recruiter and JD analyst. Extract structured information from job descriptions and return ONLY valid JSON.

Analyze the job and return this exact JSON structure:
{
  "core_skills": ["list of must-have technical skills"],
  "tools_technologies": ["tools, frameworks, platforms mentioned"],
  "responsibilities": ["key responsibilities as short bullet strings"],
  "hidden_expectations": "inferred expectations not explicitly stated (culture, ownership, pace)",
  "ats_keywords": ["important keywords for ATS resume scanning"],
  "simplified_jd": "Bullet-format simplified version in plain English. No jargon. Max 10 bullets.",
  "experience_level": "junior or mid or senior or lead",
  "role_type": "backend or frontend or fullstack or sre or data or product or other"
}

Rules:
- Return ONLY the JSON object, no markdown fences, no explanation
- core_skills: only genuinely required technical skills (max 12)
- ats_keywords: include exact phrases from the JD (max 20)
- simplified_jd: use plain English bullets, start each with a verb
- hidden_expectations: infer from tone, culture signals, stack complexity`;

const userMessage = `Job Title: ${job.role_title}\nCompany: ${job.company_name}\nLocation: ${job.location || 'India'}\n\nJob Description:\n${(job.job_description || '').substring(0, 4000)}`;

return [{
  json: {
    ...job,
    _systemPrompt: systemPrompt,
    _userMessage: userMessage
  }
}];

// Kartik's full skill profile
const KARTIK_SKILLS = new Set([
  'react', 'typescript', 'javascript', 'python', 'django', 'node.js', 'nodejs',
  'golang', 'go', 'aws', 'postgresql', 'postgres', 'mongodb', 'redis',
  'kafka', 'docker', 'snowplow', 'kinesis', 'rabbitmq', 'html', 'css',
  'rest', 'graphql', 'git', 'linux', 'sql', 'nosql', 'microservices',
  'ci/cd', 'jest', 'pytest', 'celery', 'fastapi', 's3', 'ec2', 'lambda',
  'cloudwatch', 'nginx', 'flask', 'next.js', 'nextjs', 'tailwind',
  'kubernetes', 'terraform', 'prometheus', 'grafana', 'elasticsearch'
]);

const TRANSFERABLE_MAP = {
  'vue': 'react',
  'angular': 'react',
  'spring': 'django',
  'java': 'golang',
  'scala': 'python',
  'mysql': 'postgresql',
  'dynamodb': 'mongodb',
  'sqs': 'kafka',
  'pubsub': 'kafka',
  'azure': 'aws',
  'gcp': 'aws'
};

const response = $input.item.json;
const jobData = $('Build OpenAI Prompt').item.json;

let parsed;
try {
  const content = response.choices[0].message.content;
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  parsed = {
    core_skills: [],
    tools_technologies: [],
    responsibilities: [],
    hidden_expectations: '',
    ats_keywords: [],
    simplified_jd: 'Failed to parse JD',
    experience_level: 'unknown',
    role_type: 'other'
  };
}

// Combine all mentioned skills for matching
const allJobSkills = [
  ...(parsed.core_skills || []),
  ...(parsed.tools_technologies || [])
].map(s => s.toLowerCase().trim());

// Calculate match
const matched = [];
const missing = [];
const transferable = [];

for (const skill of allJobSkills) {
  const skillKey = skill.replace(/[^a-z0-9.]/g, '');
  if (KARTIK_SKILLS.has(skill) || KARTIK_SKILLS.has(skillKey)) {
    matched.push(skill);
  } else if (TRANSFERABLE_MAP[skillKey]) {
    transferable.push({ required: skill, has: TRANSFERABLE_MAP[skillKey] });
  } else {
    missing.push(skill);
  }
}

const totalSkills = allJobSkills.length || 1;
const matchScore = Math.round(
  ((matched.length + transferable.length * 0.6) / totalSkills) * 100
);

const clampedScore = Math.min(100, Math.max(0, matchScore));

return [{
  json: {
    job_id: jobData.id,
    company_name: jobData.company_name,
    role_title: jobData.role_title,
    apply_link: jobData.apply_link,
    simplified_jd: parsed.simplified_jd || '',
    extracted_keywords: JSON.stringify(parsed.ats_keywords || []),
    core_skills: JSON.stringify(parsed.core_skills || []),
    tools_technologies: JSON.stringify(parsed.tools_technologies || []),
    responsibilities: JSON.stringify(parsed.responsibilities || []),
    hidden_expectations: parsed.hidden_expectations || '',
    ats_keywords: JSON.stringify(parsed.ats_keywords || []),
    experience_level: parsed.experience_level || 'unknown',
    role_type: parsed.role_type || 'other',
    skill_match_score: clampedScore,
    match_breakdown: JSON.stringify({
      matched_skills: matched,
      missing_skills: missing,
      transferable_skills: transferable,
      total_job_skills: totalSkills,
      score: clampedScore
    })
  }
}];

